/**
 * SQL 30-day learning MVP - daily question sets, quizzes, midterm, final.
 * Schema: departments, employees, customers, products, orders, order_items
 */

function mcq(id, topic, question, options, answer, explanation) {
  return { id, type: 'mcq', topic, question, options, answer, explanation };
}

function sqlQ(id, topic, question, expectedSql, explanation, extra = {}) {
  return { id, type: 'sql', topic, question, expectedSql, explanation, ...extra };
}

