export function getDailySet(day, setId) {
  const n = Number(day);
  const sets = DAILY_SETS[n];
  if (!sets) throw new Error(`Invalid day: ${day}. Must be 1-30.`);
  const id = String(setId).toUpperCase();
  if (!['A', 'B', 'C'].includes(id)) throw new Error(`Invalid setId: ${setId}. Must be A, B, or C.`);
  const questions = sets[id];
  if (!questions) throw new Error(`No question set ${id} for day ${day}.`);
  return questions;
}

export function getQuiz(quizNum) {
  const n = Number(quizNum);
  const quiz = QUIZZES[n];
  if (!quiz) throw new Error(`Invalid quiz: ${quizNum}. Must be 1-5 (days 5,10,15,20,25).`);
  return quiz;
}

